runtime/agent.py<pre><code>class AgentRuntime(MapFunction):
    def __init__(
        self,
        profile: BaseProfile,
        planner: LLMPlanner,
        tools: MCPRegistry,
        summarizer=None,
        max_steps: int = 6,
    ) -&gt; None:
        self.profile = profile
        self.planner = planner
        self.tools = tools
        self.summarizer = summarizer
        self.max_steps = max_steps

    def step(self, user_query: str) -&gt; str:
        plan = self.planner.plan(
            profile_system_prompt=self.profile.render_system_prompt(),
            user_query=user_query,
            tools=self.tools.describe(),
        )

        observations: List[Dict[str, Any]] = []
        reply_text: Optional[str] = None

        for i, step in enumerate(plan[: self.max_steps]):
            if step.get("type") == "reply":
                reply_text = step.get("text", "").strip()
                break
            if step.get("type") == "tool":
                name = step.get("name")
                arguments = step.get("arguments", {}) or {}
                schema = self.tools.describe().get(name, {}).get("input_schema", {})
                miss = _missing_required(arguments, schema)
                if miss:
                    observations.append(
                        {
                            "step": i,
                            "tool": name,
                            "ok": False,
                            "error": f"Missing required fields: {miss}",
                            "arguments": arguments,
                        }
                    )
                    continue
                t0 = time.time()
                try:
                    out = self.tools.call(name, arguments)
                    observations.append(
                        {
                            "step": i,
                            "tool": name,
                            "ok": True,
                            "latency_ms": int((time.time() - t0) * 1000),
                            "result": out,
                        }
                    )
                except Exception as e:
                    observations.append(
                        {
                            "step": i,
                            "tool": name,
                            "ok": False,
                            "latency_ms": int((time.time() - t0) * 1000),
                            "error": str(e),
                        }
                    )

        if reply_text:
            return reply_text
        if not observations:
            return "（没有可执行的步骤或工具返回空结果）"
        if self.summarizer:
            profile_hint = self.profile.render_system_prompt()
            messages = [
                {"role": "system", "content": "你是一个严谨的助理。只输出中文总结。"},
                {
                    "role": "user",
                    "content": f"[Profile]\n{profile_hint}\n\n[Observations]\n{observations}",
                },
            ]
            _, summary = self.summarizer.execute([None, messages])
            return summary.strip()
        return "\n".join(
            f"#{obs['step'] + 1} 工具 {obs['tool']} {'成功' if obs['ok'] else '失败'}：{obs.get('result') or obs.get('error')}"
            for obs in observations
        )

    def execute(self, data: Any) -&gt; str:
        if isinstance(data, str):
            return self.step(data)
        if isinstance(data, dict):
            ...  # 支持一次性覆写 max_steps / profile_overrides
        raise TypeError("AgentRuntime.execute 仅接受 str 或 dict 两种输入。")
</code></pre> <p>!!! info "容错要点" - <code>_missing_required(...)</code> 定义在同文件顶部，用于根据工具 <code>input_schema.required</code> 做最小必填校验 - 所有工具调用（成功/失败）都会被记录，便于调试或在 summarizer 中使用 - 默认兜底输出会逐行列出每一步执行结果</p>

examples/tutorials/transformation-api/hello_filter_world.py<pre><code>from sage.core.api.local_environment import LocalEnvironment
from sage.core.api.function.sink_function import SinkFunction
from sage.core.api.function.batch_function import BatchFunction
from sage.core.api.function.map_function import MapFunction
from sage.core.api.function.filter_function import FilterFunction
from sage.common.utils.logging.custom_logger import CustomLogger


class HelloBatch(BatchFunction):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.counter = 0
        self.max_count = 10

    def execute(self):
        if self.counter &gt;= self.max_count:
            return None
        self.counter += 1
        return f"Hello, World! #{self.counter}"


class UpperCaseMap(MapFunction):
    def execute(self, data):
        return data.upper()


class PrintSink(SinkFunction):
    def execute(self, data):
        print(data)


# 过滤器示例，过滤所有偶数结尾的数据
class Oddpicker(FilterFunction):
    def execute(self, data):
        if int(data[-1]) % 2 != 0:
            return data
        else:
            return None


def main():
    env = LocalEnvironment("Hello_Filter_World")

    env.from_batch(HelloBatch).map(UpperCaseMap).filter(Oddpicker).sink(PrintSink)

    env.submit(autostop=True)
    print("Hello Filter World 示例结束")


if __name__ == "__main__":
    # 关闭日志输出
    CustomLogger.disable_global_console_debug()
    main()
</code></pre>

examples/tutorials/transformation-api/hello_comap_world.py<pre><code># 此例意在说明如何将两个流通过comap合为一个流

from sage.core.api.local_environment import LocalEnvironment
from sage.core.api.function.sink_function import SinkFunction
from sage.common.utils.logging.custom_logger import CustomLogger
from sage.core.api.function.batch_function import BatchFunction
from sage.core.api.function.comap_function import BaseCoMapFunction


# 定义两个简单数据源：
class SourceOne(BatchFunction):
    def __init__(self):
        super().__init__()
        self.counter = 0

    def execute(self):
        self.counter += 1
        if self.counter &gt; 5:
            return None
        return {"msg": f"No.{self.counter}: Hello"}


class SourceTwo(BatchFunction):
    def __init__(self):
        super().__init__()
        self.counter = 0

    def execute(self):
        self.counter += 1
        if self.counter &gt; 10:
            return None
        return {"msg": f"World! #{self.counter}"}


class HelloCoMapProcessor(BaseCoMapFunction):
    def map0(self, data):
        return f"[Stream0] 👋 {data['msg']}"

    def map1(self, data):
        return f"[Stream1] 🌍 {data['msg']}"


class PrintSink(SinkFunction):
    def execute(self, data):
        print(data)


def main():
    env = LocalEnvironment("Hello_CoMap_World")

    # 两个数据源
    source1 = env.from_batch(SourceOne)
    source2 = env.from_batch(SourceTwo)

    # 将两个流 connect 在一起，并用 comap 分开处理
    source1.connect(source2).comap(HelloCoMapProcessor).sink(PrintSink)

    env.submit(autostop=True)
    print("Hello Comap World 示例结束")


if __name__ == "__main__":
    CustomLogger.disable_global_console_debug()
    main()
</code></pre>

